# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

class Account extends Actor with ActorLogging {
  def receive = {
    case Deposit(amount: Int) => balance += amount; log.debug("balance: %d", balance)
    case Withdrawal(amount: Int) if balance < 0 || balance - amount < 0 => log.error("overdrawn")
    case Withdrawal(amount: Int) => {
      val newBalance = balance + (-1) * amount; if (newBalance > 0) {balance += -1 * amount}; log.debug("balance: %d", balance)}
  }
}